import math

def exponential_pdf(x, lam):
    """Probability density function of Exponential(λ)"""
    if x < 0:
        return 0
    return lam * math.exp(-lam * x)

def exponential_cdf(x, lam):
    """Cumulative distribution function of Exponential(λ)"""
    if x < 0:
        return 0
    return 1 - math.exp(-lam * x)

def exponential_survival(x, lam):
    """Survival function P(X > x)"""
    if x < 0:
        return 1
    return math.exp(-lam * x)

# Example: λ = 2, find PDF, CDF at x = 1
lam = 2
x = 1
print(f"PDF at x=1: {exponential_pdf(x, lam):.4f}")
print(f"CDF at x=1: {exponential_cdf(x, lam):.4f}")
print(f"P(X > 1): {exponential_survival(x, lam):.4f}")
print(f"Mean: {1/lam}, Variance: {1/(lam**2)}")

#include <stdio.h>
#include <math.h>

// Probability density function
double exp_pdf(double x, double lam) {
    if (x < 0) return 0.0;
    return lam * exp(-lam * x);
}

// Cumulative distribution function
double exp_cdf(double x, double lam) {
    if (x < 0) return 0.0;
    return 1.0 - exp(-lam * x);
}

// Mean and variance
double exp_mean(double lam) {
    return 1.0 / lam;
}

double exp_variance(double lam) {
    return 1.0 / (lam * lam);
}

int main() {
    double lam = 2.0;
    double x = 1.0;

    printf("Exponential Distribution (λ = %.2f)\n", lam);
    printf("x = %.2f\n\n", x);
    printf("PDF: %.4f\n", exp_pdf(x, lam));
    printf("CDF: %.4f\n", exp_cdf(x, lam));
    printf("P(X > %.2f): %.4f\n", x, 1.0 - exp_cdf(x, lam));
    printf("\nMean: %.4f\n", exp_mean(lam));
    printf("Variance: %.4f\n", exp_variance(lam));
    printf("Std Dev: %.4f\n", sqrt(exp_variance(lam)));

    return 0;
}

public class ExponentialDistribution {
    private double lambda;

    public ExponentialDistribution(double lambda) {
        if (lambda <= 0) {
            throw new IllegalArgumentException("Lambda must be positive");
        }
        this.lambda = lambda;
    }

    // PDF: f(x) = λe^(-λx)
    public double pdf(double x) {
        if (x < 0) return 0.0;
        return lambda * Math.exp(-lambda * x);
    }

    // CDF: F(x) = 1 - e^(-λx)
    public double cdf(double x) {
        if (x < 0) return 0.0;
        return 1.0 - Math.exp(-lambda * x);
    }

    // Survival function: S(x) = e^(-λx)
    public double survival(double x) {
        if (x < 0) return 1.0;
        return Math.exp(-lambda * x);
    }

    // Mean = 1/λ
    public double mean() {
        return 1.0 / lambda;
    }

    // Variance = 1/λ²
    public double variance() {
        return 1.0 / (lambda * lambda);
    }

    // Median = ln(2)/λ
    public double median() {
        return Math.log(2) / lambda;
    }

    public static void main(String[] args) {
        ExponentialDistribution exp = new ExponentialDistribution(2.0);

        System.out.println("Exponential(λ=2):");
        System.out.printf("PDF(1): %.4f%n", exp.pdf(1.0));
        System.out.printf("CDF(1): %.4f%n", exp.cdf(1.0));
        System.out.printf("Mean: %.4f%n", exp.mean());
        System.out.printf("Variance: %.4f%n", exp.variance());
        System.out.printf("Median: %.4f%n", exp.median());

        // Example: component lifetime
        ExponentialDistribution component = new ExponentialDistribution(0.001);
        System.out.printf("P(X > 1000): %.4f%n", component.survival(1000));
    }
}
